import strawberry
from strawberry import Schema
from strawberry.tools import convert_sqlalchemy_to_strawberry
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker, relationship

Base = declarative_base()

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    content = Column(String)
    rating = Column(Integer)

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', backref='seller')

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    products = relationship('Product', backref='category')

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    url = Column(String)

engine = create_engine('sqlite:///example.db')
Base.metadata.create_all(engine)
Session = sessionmaker(bind=engine)

@strawberry.type
class Query:
    @strawberry.field
    def products(self) -> list['Product']:
        return Session.query(Product).all()

    @strawberry.field
    def product(self, id: int) -> 'Product':
        return Session.query(Product).get(id)

    @strawberry.field
    def reviews(self, product_id: int) -> list['Review']:
        return Session.query(Review).filter_by(product_id=product_id).all()

    @strawberry.field
    def sellers(self) -> list['Seller']:
        return Session.query(Seller).all()

    @strawberry.field
    def seller(self, id: int) -> 'Seller':
        return Session.query(Seller).get(id)

    @strawberry.field
    def categories(self) -> list['Category']:
        return Session.query(Category).all()

    @strawberry.field
    def category(self, id: int) -> 'Category':
        return Session.query(Category).get(id)

    @strawberry.field
    def images(self, product_id: int) -> list['Image']:
        return Session.query(Image).filter_by(product_id=product_id).all()

schema = Schema(Query)